function collectCapabilityWarningsForTargets(
  acc: CapabilityWarningAccumulator,
  targetAgents: AgentId[],
  capability:
    | "skills"
    | "mcpServers"
    | "agentRules"
    | "permissions"
    | "agentDefinitions",
  entryName: string,
  scope?: "global" | "repo" | "workspace",
): void {
