  it("does not validate the rules source when no targeted agents overlap", async () => {
    const dir = await makeTmpDir();
    try {
      const { actions, warnings } = await compileAgentRuleActions(
        {
          name: "my-rule",
          agents: ["claude-code"],
          path: "missing.md",
          scope: "global",
        },
        dir,
        dir,
