    assert.equal(warnings.length, 0);
    assert.equal(actions.length, 2);
    const agents = actions.map((a) => a.agent);
    assert.ok(agents.includes("claude-code"));
    assert.ok(agents.includes("codex"));
  });
});

describe("compileAgentDefinitionActions", () => {
