      assert.equal(action.agent, "claude-code");
      assert.equal(
        normalizeSlashes(action.target),
        `${repo}/CLAUDE.md`,
        `expected target at {repo}/CLAUDE.md, got: ${action.target}`,
      );
    } finally {
      await rm(dir, { recursive: true });
    }
